+      m_constraint.resize((unsigned int)dim, m_robot.na());
+      m_constraint.setMatrix(S);
+
+      for(unsigned int i=0; i<m_activeAxes.size(); i++)
+        m_constraint.vector()(i) = m_ref(m_activeAxes(i)) * m_weights(m_activeAxes(i));
